def getWithDefault(self, key, defaultValue):
    # Use the existing _findPosition helper method
    ndx = self._findPosition(key)

    # If key is found, return its value
    if ndx is not None:
        return self._entryList[ndx].value
    else:
        # If key is not found, return the default value
        return defaultValue
